   input [1:0] sel;
   output out;


   reg out;

   always @ (obf_a or b or c or d or sel) begin
      case (sel)
         2'b00: out = obf_a;
         2'b01: out = b;
         2'b10: out = c;
         2'b11: out = d;
         default: out = obf_a;
      endcase
   end

endmodule
